def executeCommand():
    import subprocess

    # Example of validating the command using regex (not perfect but can be improved)
    def is_valid(command):
        return all([re.match('^[a-zA-Z0-9_\-]+$', cmd) for cmd in command.split()])

    user_input = input("Enter the command: ")
    if not is_valid(user_input):
        print("Invalid command format, please try again.")
        return

    # Execute the command using subprocess module
    process = subprocess.Popen(user_input, shell=True, stdout=subprocess.PIPE)
    output, _ = process.communicate()

    if process.returncode == 0:
        print("Command executed successfully.")
    else:
        print("Command failed with error code:", process.returncode)

